import React, { useState, useEffect } from 'react';
import {
  Search, Calendar, Users, Star, MapPin, ChevronRight,
  Sparkles, Shield, Clock, Waves, Diamond
} from 'lucide-react';
import Swal from 'sweetalert2';
import Login from './Login';
import Dashboard from './Dashboard';
import AdminDashboard from './AdminDashboard';
import HotelAdminRegister from './HotelAdminRegister';
import authService from './services/authService';

const App = () => {
  const [scrolled, setScrolled] = useState(false);
  const [currentPage, setCurrentPage] = useState('home');
  const [user, setUser] = useState(null);

  useEffect(() => {
    const loggedInUser = authService.getCurrentUser();

    if (loggedInUser) {
      setUser(loggedInUser);

      if (loggedInUser.role === 'admin') {
        setCurrentPage('admin');
      } else {
        setCurrentPage('dashboard');
      }
    }

    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleLogin = (userData) => {
    setUser(userData);

    if (userData.role === 'admin') {
      setCurrentPage('admin');
    } else {
      setCurrentPage('dashboard');
    }
  };

  const handleLogout = () => {
    authService.logout();
    setUser(null);
    setCurrentPage('home');
  };

  // HOTEL ADMIN REGISTRATION SUCCESS HANDLER
  const handleHotelPartnerRegister = () => {
    Swal.fire({
      icon: 'success',
      title: 'Registration Submitted',
      text: 'Your hotel admin account is pending approval from system admin.',
      confirmButtonColor: '#06b6d4'
    });

    setCurrentPage('home');
  };

  // ADMIN DASHBOARD
  if (currentPage === 'admin' && user?.role === 'admin') {
    return <AdminDashboard user={user} onLogout={handleLogout} />;
  }

  // USER DASHBOARD
  if (currentPage === 'dashboard' && user) {
    return <Dashboard user={user} onLogout={handleLogout} />;
  }

  // LOGIN
  if (currentPage === 'login') {
    return <Login onLogin={handleLogin} />;
  }

  // HOTEL ADMIN REGISTER PAGE
  if (currentPage === 'partner') {
    return (
      <HotelAdminRegister
        onSuccess={handleHotelPartnerRegister}
        onBack={() => setCurrentPage('home')}
      />
    );
  }

  return (
    <div className="min-h-screen bg-slate-950 text-white overflow-x-hidden relative">

      {/* Background */}
      <div className="fixed inset-0 z-0 pointer-events-none">
        <div className="absolute inset-0 bg-gradient-to-br from-slate-950 via-purple-950/20 to-slate-950" />
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-purple-600/10 rounded-full blur-3xl animate-pulse" />
        <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-cyan-600/10 rounded-full blur-3xl animate-pulse delay-1000" />
      </div>

      {/* NAVBAR */}
      <nav className={`fixed w-full z-50 transition-all duration-500 ${scrolled ? 'bg-slate-950/80 backdrop-blur-xl border-b border-white/10' : 'bg-transparent'}`}>
        <div className="max-w-7xl mx-auto px-6 py-4 flex justify-between items-center">

          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setCurrentPage('home')}>
            <Diamond className="w-8 h-8 text-cyan-400" />
            <span className="text-2xl font-bold bg-gradient-to-r from-cyan-400 to-purple-400 bg-clip-text text-transparent">
              AI'STAY
            </span>
          </div>

          <div className="hidden md:flex items-center gap-8">

            {/* REMOVED: Destinations & Experiences */}

            {/* NEW: LET'S PARTNER */}
            <button
              onClick={() => setCurrentPage('partner')}
              className="text-gray-300 hover:text-cyan-400 transition-colors font-medium"
            >
              Let's Partner
            </button>

            {user ? (
              <button
                onClick={() => setCurrentPage(user.role === 'admin' ? 'admin' : 'dashboard')}
                className="px-6 py-2 bg-gradient-to-r from-cyan-500 to-purple-600 rounded-full font-medium"
              >
                Dashboard
              </button>
            ) : (
              <button
                onClick={() => setCurrentPage('login')}
                className="px-6 py-2 bg-gradient-to-r from-cyan-500 to-purple-600 rounded-full font-medium"
              >
                Sign In
              </button>
            )}

          </div>
        </div>
      </nav>

      {/* HERO */}
      <section className="relative z-10 pt-32 pb-20 px-6">
        <div className="max-w-7xl mx-auto text-center">

          <h1 className="text-5xl md:text-7xl font-bold mb-6">
            Discover Your
            <span className="block bg-gradient-to-r from-cyan-400 to-purple-400 bg-clip-text text-transparent">
              Perfect Escape
            </span>
          </h1>

          <button
            onClick={() => user ? setCurrentPage('dashboard') : setCurrentPage('login')}
            className="mt-8 px-8 py-4 bg-gradient-to-r from-cyan-500 to-purple-500 rounded-2xl font-bold"
          >
            Find Stays
          </button>

        </div>
      </section>

    </div>
  );
};

export default App;
